// Frita – Employee ID Lookup
// Normalizes spoken employee ID and looks up in known callers.
// -----------------------------------------------
// TODO: Replace hardcoded lookup with n8n Table node:
//   Table: fv_known_callers
//   Operation: Get rows where employee_id = normalized input AND active = true
// -----------------------------------------------

// Normalize spoken numbers to digits
const numberWords = {
  'zero': '0', 'oh': '0', 'o': '0',
  'one': '1', 'two': '2', 'three': '3',
  'four': '4', 'five': '5', 'six': '6',
  'seven': '7', 'eight': '8', 'nine': '9',
  'ten': '10'
};

const speech = ($json.body?.SpeechResult || '').toLowerCase().trim();

// Convert spoken words to digits, or use raw if already numeric
let employeeId;
if (/^\d+$/.test(speech.replace(/\s+/g, ''))) {
  // Already digits (possibly with spaces: "1 0 0 4 2")
  employeeId = speech.replace(/\s+/g, '');
} else {
  // Spoken words: "one zero zero four two"
  employeeId = speech.split(/\s+/).map(w => numberWords[w] || w).join('');
}

// Hardcoded known callers (replace with n8n Table)
const knownCallers = [
  {
    phone_number: '+18177156827',
    email: 'joel.blagg@resolve.io',
    employee_id: '1234',
    first_name: 'Joel',
    last_name: 'Blagg',
    active: true
  },
  {
    phone_number: '+16785523640',
    email: 'nelson.veiga@resolve.io',
    employee_id: '2345',
    first_name: 'Nelson',
    last_name: 'Veiga',
    active: true
  },
  {
    phone_number: '+13479985254',
    email: 'derek.pascarella@resolve.io',
    employee_id: '3456',
    first_name: 'Derek',
    last_name: 'Pascarella',
    active: true
  },
  {
    phone_number: '+14084318627',
    email: 'alex.yupanqui@resolve.io',
    employee_id: '4567',
    first_name: 'Alex',
    last_name: 'Yupanqui',
    active: true
  }
];

const match = knownCallers.find(
  c => c.employee_id === employeeId && c.active
);

if (match) {
  return {
    json: {
      found: true,
      first_name: match.first_name,
      last_name: match.last_name,
      employee_id: employeeId,
      phone_number: match.phone_number,
      email: match.email
    }
  };
}

return {
  json: {
    found: false,
    employee_id: employeeId
  }
};
